// Thin fetch wrapper. The legacy frontend hand-rolls JSON.stringify + content-type
// headers at every call site; centralizing them here keeps island code focused
// on the data, not the wire format. Throws on non-2xx so callers can `try/catch`
// once and surface the message via the legacy toast helper.

export async function getJson<T>(url: string): Promise<T> {
  const res = await fetch(url);
  if (!res.ok) {
    throw new Error(`${res.status} ${res.statusText}: ${await res.text()}`);
  }
  return (await res.json()) as T;
}

export async function postJson<T>(url: string, body: unknown): Promise<T> {
  const res = await fetch(url, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify(body),
  });
  if (!res.ok) {
    throw new Error(`${res.status} ${res.statusText}: ${await res.text()}`);
  }
  return (await res.json()) as T;
}
